import {
  Grid,
  Box,
  Pagination,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Typography,
} from "@mui/material";
import { useCallback, useEffect, useState } from "react";
import api from "../../utils/api";
import GalleryCard from "../GalleryCard";

export default function CardLibrary() {
  const [cards, setCards] = useState([]);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [rarity, setRarity] = useState("");
  const [affix, setAffix] = useState("");

  const fetchCards = useCallback(async () => {
    const res = await api.get("/cards/my", {
      params: {
        page,
        rarity: rarity || undefined,
        affix: affix || undefined,
      },
    });
    const rarityOrder = ["legendary", "epic", "rare", "uncommon", "common"];
    const sortedCards = res.data.sort((a, b) => {
      if (a.rarity !== b.rarity) {
        return rarityOrder.indexOf(a.rarity) - rarityOrder.indexOf(b.rarity);
      }
      return a.name.localeCompare(b.name);
    });
    setCards(sortedCards);
    setPages(res.pages);
  }, [page, rarity, affix]);

  useEffect(() => {
    fetchCards();
  }, [fetchCards]);

  return (
    <Box>
      <Box display="flex" gap={2} mb={3} flexWrap="wrap">
        <FormControl size="small">
          <InputLabel>Rarity</InputLabel>
          <Select
            value={rarity}
            label="Rarity"
            onChange={(e) => {
              setPage(1);
              setRarity(e.target.value);
            }}
            sx={{ minWidth: 140 }}
          >
            <MenuItem value="">All</MenuItem>
            <MenuItem value="common">Common</MenuItem>
            <MenuItem value="uncommon">Uncommon</MenuItem>
            <MenuItem value="rare">Rare</MenuItem>
            <MenuItem value="epic">Epic</MenuItem>
            <MenuItem value="legendary">Legendary</MenuItem>
          </Select>
        </FormControl>

        <FormControl size="small">
          <InputLabel>Affix</InputLabel>
          <Select
            value={affix}
            label="Affix"
            onChange={(e) => {
              setPage(1);
              setAffix(e.target.value);
            }}
            sx={{ minWidth: 140 }}
          >
            <MenuItem value="">All</MenuItem>
            <MenuItem value="Shiny">Shiny</MenuItem>
            <MenuItem value="Angry">Angry</MenuItem>
            <MenuItem value="Tough">Tough</MenuItem>
            <MenuItem value="Swift">Swift</MenuItem>
            <MenuItem value="Blessed">Blessed</MenuItem>
          </Select>
        </FormControl>
      </Box>

      {cards.length > 0 ? (
        <Grid container spacing={3}>
          {cards.map((card) => (
            <Grid item xs={12} sm={6} md={4} lg={3} key={card.userCardId}>
              <GalleryCard card={card} />
            </Grid>
          ))}
        </Grid>
      ) : (
        <Box
          display="flex"
          justifyContent="center"
          alignItems="center"
          minHeight="200px"
        >
          <Typography variant="h6" color="text.secondary" textAlign="center">
            {rarity || affix
              ? "No cards match your selected filters."
              : "You have no cards in your collection."}
          </Typography>
        </Box>
      )}

      <Box display="flex" justifyContent="center" mt={4}>
        <Pagination
          count={pages}
          page={page}
          onChange={(_, value) => setPage(value)}
          color="primary"
        />
      </Box>
    </Box>
  );
}
