import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function AbilitiesTable() {
  const [selected, setSelected] = useState(null);
  const [open, setOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [tableState, setTableState] = useState({
    page: 0,
    limit: 10,
    search: "",
  });

  const tableSetters = {
    setPage: (page) => setTableState((prev) => ({ ...prev, page })),
    setLimit: (limit) => setTableState((prev) => ({ ...prev, limit })),
    setSearch: (search) => setTableState((prev) => ({ ...prev, search })),
  };

  const columns = [
    { field: "name", headerName: "Name" },
    { field: "description", headerName: "Description" },
    { field: "value", headerName: "Value", type: "object" },
    { field: "probability", headerName: "Probability" },
    { field: "types", headerName: "Types", type: "array" },
  ];

  const fetchAbilities = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/abilities", { params });
  };

  const handleEdit = (row) => {
    setSelected(row);
    setOpen(true);
  };

  const handleDelete = async (row) => {
    if (confirm(`Delete ability ${row.name}?`)) {
      await api.delete(`/abilities/${row._id}`);
      setRefreshKey((prev) => prev + 1);
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchAbilities}
        columns={columns}
        onEdit={handleEdit}
        onDelete={handleDelete}
        tableState={tableState}
        tableSetters={tableSetters}
        refreshKey={refreshKey}
      />

      {open && (
        <AdminFormDialog
          entity={selected}
          endpoint="/abilities"
          columns={columns}
          title="Ability"
          onClose={() => {
            setOpen(false);
            setRefreshKey((prev) => prev + 1);
          }}
        />
      )}
    </>
  );
}
