import { Box, Card, CardContent, Chip, Stack, Typography } from "@mui/material";
import CodexPanel from "./CodexPanel";
import SmartCardImage from "./SmartCardImage";

function EnemyItem({ enemy }) {
  return (
    <Card
      sx={{
        minHeight: 620,
        display: "flex",
        flexDirection: "column",
        border: "2px solid",
        borderColor: "divider",
        borderRadius: 3,
        transition: "0.2s",
        "&:hover": {
          transform: "translateY(-4px) scale(1.02)",
          boxShadow: 6,
        },
      }}
    >
      {enemy.imageUrl ? (
        <SmartCardImage src={enemy.imageUrl} alt={enemy.name} />
      ) : (
        <Box sx={{ aspectRatio: "3 / 2", minHeight: 220, backgroundColor: "background.default" }} />
      )}
      <CardContent sx={{ display: "flex", flexDirection: "column", flexGrow: 1, overflow: "hidden" }}>
        <Typography fontWeight={700}>{enemy.name}</Typography>
        <Typography variant="body2">
          HP: {enemy.hp} | ATK: {enemy.attack} | SPD: {enemy.speed}
        </Typography>

        <Box sx={{ mt: 1, flexGrow: 1, overflowY: "auto", pr: 1 }}>
          <Typography variant="body2" color="text.secondary">
            {enemy.description}
          </Typography>
          {Array.isArray(enemy.abilities) && enemy.abilities.length > 0 ? (
            <Typography variant="body2" sx={{ mt: 1 }}>
              Abilities: {enemy.abilities.join(", ")}
            </Typography>
          ) : null}
        </Box>

        <Stack direction="row" spacing={1} sx={{ mt: 1, flexWrap: "wrap" }} useFlexGap>
          {enemy.difficulty ? <Chip size="small" label={`Difficulty: ${enemy.difficulty}`} /> : null}
          {enemy.level !== undefined ? <Chip size="small" label={`Level: ${enemy.level}`} /> : null}
          {enemy.maxCards !== undefined ? <Chip size="small" label={`Max Cards: ${enemy.maxCards}`} /> : null}
        </Stack>
      </CardContent>
    </Card>
  );
}

export default function CodexEnemies() {
  return (
    <CodexPanel
      endpoint="/enemies/codex"
      entityKey="Enemies"
      emptyMessage="No enemies found in the codex."
      renderCard={(item) => <EnemyItem enemy={item} />}
    />
  );
}



