import { Box, Card, CardContent, Chip, Stack, Typography } from "@mui/material";
import CodexPanel from "./CodexPanel";
import SmartCardImage from "./SmartCardImage";

const rarityColors = {
  common: "#808080",
  uncommon: "#00ff00",
  rare: "#0080ff",
  epic: "#8000ff",
  legendary: "#ff8000",
};

function CardItem({ card }) {
  const rarity = card.rarity || "common";

  return (
    <Card
      sx={{
        minHeight: 620,
        display: "flex",
        flexDirection: "column",
        border: `2px solid ${rarityColors[rarity] || rarityColors.common}`,
        borderRadius: 3,
        transition: "0.2s",
        "&:hover": {
          transform: "translateY(-4px) scale(1.02)",
          boxShadow: 6,
        },
      }}
    >
      {card.imageUrl ? (
        <SmartCardImage src={card.imageUrl} alt={card.name} />
      ) : (
        <Box sx={{ aspectRatio: "3 / 2", minHeight: 220, backgroundColor: "background.default" }} />
      )}
      <CardContent sx={{ display: "flex", flexDirection: "column", flexGrow: 1, overflow: "hidden" }}>
        <Typography fontWeight={700}>{card.name}</Typography>
        <Typography variant="body2">
          HP: {card.hp} | ATK: {card.attack} | SPD: {card.speed}
        </Typography>

        <Box sx={{ mt: 1, flexGrow: 1, overflowY: "auto", pr: 1 }}>
          <Typography variant="body2" color="text.secondary">
            {card.description}
          </Typography>
        </Box>

        <Stack direction="row" spacing={1} sx={{ mt: 1, flexWrap: "wrap" }} useFlexGap>
          <Chip size="small" label={rarity} />
          {card.type ? <Chip size="small" label={card.type} /> : null}
          {card.value !== undefined ? <Chip size="small" label={`Value: ${card.value}`} /> : null}
          {Array.isArray(card.affixes)
            ? card.affixes.map((affix) => <Chip key={affix} size="small" label={affix} />)
            : null}
        </Stack>
      </CardContent>
    </Card>
  );
}

export default function CodexCards() {
  return (
    <CodexPanel
      endpoint="/cards/codex"
      entityKey="Cards"
      emptyMessage="No cards found in the codex."
      renderCard={(item) => <CardItem card={item} />}
    />
  );
}



