import { Box, CircularProgress, Grid, InputAdornment, Pagination, TextField, Typography } from "@mui/material";
import { useCallback, useEffect, useState } from "react";
import api from "../../utils/api";

export default function CodexPanel({ endpoint, entityKey, renderCard, emptyMessage }) {
  const [items, setItems] = useState([]);
  const [page, setPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [search, setSearch] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [loading, setLoading] = useState(false);
  const showSearchSpinner = loading || search !== debouncedSearch;

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      setDebouncedSearch(search);
    }, 2000);

    return () => clearTimeout(timeoutId);
  }, [search]);

  const fetchItems = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get(endpoint, {
        params: {
          page,
          limit: 12,
          search: debouncedSearch || undefined,
        },
      });
      setItems(res.data);
      setPages(res.pages || 1);
    } finally {
      setLoading(false);
    }
  }, [endpoint, page, debouncedSearch]);

  useEffect(() => {
    fetchItems();
  }, [fetchItems]);

  return (
    <Box>
      <Box display="flex" mb={3}>
        <TextField
          size="small"
          label={`Search ${entityKey}`}
          value={search}
          onChange={(e) => {
            setPage(1);
            setSearch(e.target.value);
          }}
          InputProps={{
            endAdornment: showSearchSpinner ? (
              <InputAdornment position="end">
                <CircularProgress size={16} />
              </InputAdornment>
            ) : null,
          }}
          sx={{ minWidth: 260 }}
        />
      </Box>

      {items.length > 0 ? (
        <Grid container spacing={3}>
          {items.map((item) => (
            <Grid item xs={12} sm={6} md={4} lg={3} key={item._id || item.name}>
              {renderCard(item)}
            </Grid>
          ))}
        </Grid>
      ) : (
        <Box display="flex" justifyContent="center" alignItems="center" minHeight="200px">
          <Typography variant="h6" color="text.secondary" textAlign="center">
            {emptyMessage}
          </Typography>
        </Box>
      )}

      <Box display="flex" justifyContent="center" mt={4}>
        <Pagination
          count={pages}
          page={page}
          onChange={(_, value) => setPage(value)}
          color="primary"
        />
      </Box>
    </Box>
  );
}
