import { createContext, useContext, useState, useEffect, useRef } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import api, { getBaseURL } from "../utils/api";
import { jwtDecode } from "jwt-decode";
import axios from "axios";

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const refreshPromiseRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    // Check for tokens in URL params (from Discord OAuth callback)
    const urlParams = new URLSearchParams(window.location.search);
    const accessToken = urlParams.get("access_token");
    const refreshToken = urlParams.get("refresh_token");

    if (accessToken && refreshToken) {
      // Store tokens
      localStorage.setItem("accessToken", accessToken);
      localStorage.setItem("refreshToken", refreshToken);

      // Clean up URL
      window.history.replaceState({}, document.title, location.pathname);

      // Fetch user info
      fetchUser();
    } else {
      // Check for existing token
      const token = localStorage.getItem("accessToken");
      if (token) {
        fetchUser();
      } else {
        setLoading(false);
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fetchUser = async () => {
    const accessToken = localStorage.getItem("accessToken");

    if (accessToken) {
      try {
        const decodedToken = jwtDecode(accessToken);
        const currentTime = Date.now() / 1000;

        if (decodedToken.exp < currentTime) {
          // Token has expired, attempt to refresh
          const refreshed = await refreshAccessToken();
          if (!refreshed) {
            setLoading(false);
            return;
          }
        } else {
          // Token is still valid
        }

        const userData = await api.get("/auth/me");
        setUser(userData.user);
        setLoading(false);
      } catch (error) {
        // Handle decoding or token issues
        localStorage.removeItem("accessToken");
        localStorage.removeItem("refreshToken");
        setUser(null);
        setLoading(false);
      }
    } else {
      setLoading(false);
    }
  };

  const login = () => {
    // Redirect to Discord OAuth using the correct API base URL
    const apiBaseURL = getBaseURL();
    const discordUrl =
      `${apiBaseURL}/auth/discord?redirect_uri=` +
      encodeURIComponent(window.location.origin);
    console.log("[Auth] Redirecting to Discord OAuth:", discordUrl);
    window.location.href = discordUrl;
  };

  const logout = async () => {
    try {
      await api.post("/auth/logout");
    } catch (error) {
      console.error("Logout error:", error);
    } finally {
      localStorage.removeItem("accessToken");
      localStorage.removeItem("refreshToken");
      setUser(null);
      navigate("/login");
    }
  };

  const refreshAccessToken = async () => {
    if (refreshPromiseRef.current) {
      return refreshPromiseRef.current;
    }

    const refreshToken = localStorage.getItem("refreshToken");

    if (refreshToken) {
      refreshPromiseRef.current = (async () => {
        try {
          const response = await axios.post(`${getBaseURL()}/auth/refresh`, { refreshToken });
          const { accessToken: newAccessToken, refreshToken: newRefreshToken } = response.data;

          localStorage.setItem("accessToken", newAccessToken);
          localStorage.setItem("refreshToken", newRefreshToken);
          return true;
        } catch (error) {
          console.error("Refresh token error:", error);
          localStorage.removeItem("accessToken");
          localStorage.removeItem("refreshToken");
          setUser(null);
          navigate("/login");
          return false;
        } finally {
          refreshPromiseRef.current = null;
        }
      })();

      return refreshPromiseRef.current;
    } else {
      // No refresh token available, need to login again
      localStorage.removeItem("accessToken");
      localStorage.removeItem("refreshToken");
      setUser(null);
      navigate("/login");
      return false;
    }
  };

  const value = {
    user,
    loading,
    login,
    logout,
    refreshUser: fetchUser,
    refreshAccessToken, // Add the function to the context value
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}
