import { Box, Tab, Tabs } from "@mui/material";
import { useState } from "react";
import CardLibrary from "../components/gallery/CardLibrary";
import GalleryCodex from "../components/gallery/GalleryCodex";

export default function GalleryPage() {
  const [activeSection, setActiveSection] = useState("library");

  return (
    <Box>
      <Tabs
        value={activeSection}
        onChange={(_, nextValue) => setActiveSection(nextValue)}
        sx={{ mb: 3 }}
      >
        <Tab label="Card Library" value="library" />
        <Tab label="Codex" value="codex" />
      </Tabs>

      {activeSection === "library" ? <CardLibrary /> : <GalleryCodex />}
    </Box>
  );
}
