// src/components/admin/PacksTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function PacksTable() {
  const [selectedPack, setSelectedPack] = useState(null);
  const [open, setOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [tableState, setTableState] = useState({
    page: 0,
    limit: 10,
    search: "",
  });

  const tableSetters = {
    setPage: (page) => setTableState((prev) => ({ ...prev, page })),
    setLimit: (limit) => setTableState((prev) => ({ ...prev, limit })),
    setSearch: (search) => setTableState((prev) => ({ ...prev, search })),
  };

  const packColumns = [
    { field: "name", headerName: "Name" },
    { field: "description", headerName: "Description" },
    { field: "size", headerName: "Size", type: "number" },
    { field: "price", headerName: "Price", type: "number" },
    {
      field: "affixChance",
      headerName: "Affix Chance (1-100)%",
      type: "number",
      range: "1-100",
    },
    {
      field: "rarityDistribution",
      headerName: "rarityDistribution",
      type: "object",
    },
  ];

  const fetchPacks = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/packs", { params });
  };

  const handleEdit = (pack) => {
    setSelectedPack(pack);
    setOpen(true);
  };

  const handleDelete = async (pack) => {
    if (confirm(`Delete pack ${pack.name}?`)) {
      await api.delete(`/packs/${pack._id}`);
      setRefreshKey((prev) => prev + 1);
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchPacks}
        columns={packColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
        tableState={tableState}
        tableSetters={tableSetters}
        refreshKey={refreshKey}
      />
      {open && (
        <AdminFormDialog
          entity={selectedPack}
          endpoint="/packs"
          columns={packColumns}
          title="Pack"
          onClose={() => {
            setOpen(false);
            setRefreshKey((prev) => prev + 1);
          }}
        />
      )}
    </>
  );
}
