// src/components/admin/UsersTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function UsersTable() {
  const [selectedUser, setSelectedUser] = useState(null);
  const [open, setOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [tableState, setTableState] = useState({
    page: 0,
    limit: 10,
    search: "",
  });

  const tableSetters = {
    setPage: (page) => setTableState((prev) => ({ ...prev, page })),
    setLimit: (limit) => setTableState((prev) => ({ ...prev, limit })),
    setSearch: (search) => setTableState((prev) => ({ ...prev, search })),
  };

  const userColumns = [
    { field: "settings.username", headerName: "Username", hideInForm: true },
    { field: "balance", headerName: "Balance", type: "number" },
    { field: "roles", headerName: "Roles", type: "array" },
  ];

  const fetchUsers = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/users", { params });
  };

  const handleEdit = (user) => {
    setSelectedUser(user);
    setOpen(true);
  };

  const handleDelete = async (user) => {
    if (confirm(`Delete user ${user.username}?`)) {
      await api.delete(`/users/${user._id}`);
      setRefreshKey((prev) => prev + 1);
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchUsers}
        columns={userColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
        tableState={tableState}
        tableSetters={tableSetters}
        refreshKey={refreshKey}
      />
      {open && (
        <AdminFormDialog
          entity={selectedUser}
          endpoint="/users"
          columns={userColumns}
          title="User"
          onClose={() => {
            setOpen(false);
            setRefreshKey((prev) => prev + 1);
          }}
        />
      )}
    </>
  );
}
