// src/components/admin/CardsTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function CardsTable() {
  const [selectedCard, setSelectedCard] = useState(null);
  const [open, setOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [tableState, setTableState] = useState({
    page: 0,
    limit: 10,
    search: "",
  });

  const tableSetters = {
    setPage: (page) => setTableState((prev) => ({ ...prev, page })),
    setLimit: (limit) => setTableState((prev) => ({ ...prev, limit })),
    setSearch: (search) => setTableState((prev) => ({ ...prev, search })),
  };

  const cardColumns = [
    { field: "uniqueId", headerName: "Card ID", hideInForm: true },
    { field: "description", headerName: "Description" },
    { field: "imageUrl", headerName: "Image URL", type: "image" },
    { field: "attack", headerName: "Attack", type: "number" },
    { field: "hp", headerName: "HP", type: "number" },
    { field: "speed", headerName: "Speed", type: "number" },
    { field: "value", headerName: "Value", type: "number" },
    { field: "type", headerName: "Type" },
  ];

  const fetchCards = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/cards", { params });
  };

  const handleEdit = (card) => {
    setSelectedCard(card);
    setOpen(true);
  };

  const handleDelete = async (card) => {
    if (confirm(`Delete card ${card.uniqueId}?`)) {
      await api.delete(`/cards/${card._id}`);
      setRefreshKey((prev) => prev + 1);
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchCards}
        columns={cardColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
        tableState={tableState}
        tableSetters={tableSetters}
        refreshKey={refreshKey}
      />
      {open && (
        <AdminFormDialog
          entity={selectedCard}
          endpoint="/cards"
          columns={cardColumns}
          title="Cards"
          onClose={() => {
            setOpen(false);
            setRefreshKey((prev) => prev + 1);
          }}
        />
      )}
    </>
  );
}
