import { useState, useEffect } from "react";
import {
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
  TablePagination,
  IconButton,
  TextField,
  Box,
  CircularProgress,
  InputAdornment,
  LinearProgress,
} from "@mui/material";
import { Edit, Delete } from "@mui/icons-material";

function getValue(obj, path) {
  if (!path) return "";
  return path.split(".").reduce((acc, part) => acc?.[part], obj);
}

function renderValue(value) {
  if (value === null || value === undefined) return "";

  if (Array.isArray(value)) {
    return value.join(", ");
  }

  if (typeof value === "object") {
    if (value.name) return value.name;
    if (value.username) return value.username;
    return JSON.stringify(value);
  }

  return value.toString();
}

export default function DataTable({
  fetchData,
  columns,
  onEdit,
  onDelete,
  tableState,
  tableSetters,
  refreshKey = 0,
}) {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);

  const page = tableState?.page ?? 0;
  const limit = tableState?.limit ?? 10;
  const search = tableState?.search ?? "";
  const [searchInput, setSearchInput] = useState(search);

  const setPage = tableSetters?.setPage ?? (() => {});
  const setLimit = tableSetters?.setLimit ?? (() => {});
  const setSearch = tableSetters?.setSearch ?? (() => {});
  const isSearchPending = searchInput !== search;
  const showSearchLoading = isSearchPending || (loading && searchInput.trim() !== "");

  useEffect(() => {
    setSearchInput(search);
  }, [search]);

  useEffect(() => {
    const timeout = setTimeout(() => {
      if (searchInput !== search) {
        setPage(0);
        setSearch(searchInput);
      }
    }, 2000);

    return () => clearTimeout(timeout);
  }, [searchInput, search]);

  const loadData = async () => {
    setLoading(true);
    try {
      const response = await fetchData({ page, limit, search });
      setData(response.data);
      setTotal(response.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, [fetchData, page, limit, search, refreshKey]);

  return (
    <Box>
      {loading && <LinearProgress sx={{ mb: 1 }} />}
      <TextField
        label="Search"
        variant="outlined"
        size="small"
        value={searchInput}
        onChange={(e) => setSearchInput(e.target.value)}
        helperText={showSearchLoading ? "Searching..." : " "}
        InputProps={{
          endAdornment: showSearchLoading ? (
            <InputAdornment position="end">
              <CircularProgress size={18} />
            </InputAdornment>
          ) : null,
        }}
        sx={{ mb: 2 }}
      />

      <Table>
        <TableHead>
          <TableRow>
            {columns?.map((col) => (
              <TableCell key={col.field}>{col.headerName}</TableCell>
            ))}
            <TableCell>Actions</TableCell>
          </TableRow>
        </TableHead>

        <TableBody>
          {loading ? (
            <TableRow>
              <TableCell colSpan={columns.length + 1}>Loading...</TableCell>
            </TableRow>
          ) : data?.length === 0 ? (
            <TableRow>
              <TableCell colSpan={columns.length + 1}>
                No records found
              </TableCell>
            </TableRow>
          ) : (
            data.map((row) => (
              <TableRow key={row._id}>
                {columns.map((col) => {
                  const rawValue = getValue(row, col.field);

                  return (
                    <TableCell key={row._id + col.field}>
                      {col.render ? col.render(rawValue, row) : renderValue(rawValue)}
                    </TableCell>
                  );
                })}

                <TableCell>
                  <IconButton onClick={() => onEdit(row)}>
                    <Edit />
                  </IconButton>
                  <IconButton onClick={() => onDelete(row)}>
                    <Delete />
                  </IconButton>
                </TableCell>
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>

      <TablePagination
        component="div"
        count={total}
        page={page}
        onPageChange={(e, newPage) => setPage(newPage)}
        rowsPerPage={limit}
        onRowsPerPageChange={(e) => {
          setLimit(parseInt(e.target.value, 10));
          setPage(0);
        }}
      />
    </Box>
  );
}
