import { useState, useEffect } from "react";
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
  Box,
} from "@mui/material";
import api from "../../../utils/api";

export default function AdminFormDialog({
  entity,
  endpoint,
  columns,
  title,
  onClose,
}) {
  const isEdit = Boolean(entity);
  const [form, setForm] = useState({});
  const [errors, setErrors] = useState({});

  const getValueByPath = (obj, path) => {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, part) => acc?.[part], obj);
  };

  const serializeValue = (value, type) => {
    if (value === null || value === undefined) return "";
    if (type === "object" || type === "array") {
      try {
        return JSON.stringify(value, null, 2);
      } catch {
        return "";
      }
    }
    return String(value);
  };

  const deserializeValue = (value, type) => {
    if (typeof value !== "string") return value;
    const trimmed = value.trim();

    if (type === "number") {
      if (trimmed === "") return "";
      const parsed = Number(trimmed);
      return Number.isNaN(parsed) ? value : parsed;
    }

    if (type === "object") {
      if (trimmed === "") return {};
      try {
        const parsed = JSON.parse(trimmed);
        return parsed && typeof parsed === "object" && !Array.isArray(parsed)
          ? parsed
          : value;
      } catch {
        return value;
      }
    }

    if (type === "array") {
      if (trimmed === "") return [];
      try {
        const parsed = JSON.parse(trimmed);
        return Array.isArray(parsed) ? parsed : value;
      } catch {
        return value;
      }
    }

    return value;
  };

  const parseNumberRange = (range) => {
    if (!range) return null;

    if (typeof range === "string") {
      const [rawMin, rawMax] = range.split("-");
      const min = Number(rawMin?.trim());
      const max = Number(rawMax?.trim());
      if (Number.isFinite(min) && Number.isFinite(max)) {
        return { min, max };
      }
      return null;
    }

    if (typeof range === "object") {
      const min = Number(range.min);
      const max = Number(range.max);
      if (Number.isFinite(min) && Number.isFinite(max)) {
        return { min, max };
      }
    }

    return null;
  };

  useEffect(() => {
    if (entity) {
      const serialized = {};
      columns.forEach((c) => {
        serialized[c.field] = serializeValue(getValueByPath(entity, c.field), c.type);
      });
      setForm(serialized);
    } else {
      const initial = {};
      columns.forEach((c) => {
        if (c.type === "object") {
          initial[c.field] = "{}";
        } else if (c.type === "array") {
          initial[c.field] = "[]";
        } else {
          initial[c.field] = "";
        }
      });
      setForm(initial);
    }
  }, [entity, columns]);

  const handleChange = (field, value) => {
    setForm((prev) => ({ ...prev, [field]: value }));
    setErrors((prev) => ({ ...prev, [field]: "" }));
  };

  const handleSubmit = async () => {
    try {
      const payload = {};
      const nextErrors = {};

      columns.forEach((col) => {
        if (col.hideInForm) return;

        const parsedValue = deserializeValue(form[col.field], col.type);
        if (col.type === "number") {
          const range = parseNumberRange(col.range);
          if (range && parsedValue !== "") {
            const numericValue = Number(parsedValue);
            if (!Number.isFinite(numericValue)) {
              nextErrors[col.field] = "Please enter a valid number.";
            } else if (numericValue < range.min || numericValue > range.max) {
              nextErrors[col.field] = `Must be between ${range.min} and ${range.max}.`;
            }
          }
        }

        payload[col.field] = parsedValue;
      });

      if (Object.keys(nextErrors).length > 0) {
        setErrors(nextErrors);
        return;
      }

      if (isEdit) {
        await api.patch(`${endpoint}/${entity._id}`, payload);
      } else {
        await api.post(endpoint, payload);
      }

      onClose(true);
    } catch (err) {
      console.error("Save error:", err);
      alert("Failed to save");
    }
  };

  return (
    <Dialog open onClose={() => onClose(false)} fullWidth maxWidth="sm">
      <DialogTitle>{isEdit ? `Edit ${title}` : `Create ${title}`}</DialogTitle>

      <DialogContent dividers>
        {columns.map((col) => {
          if (col.hideInForm) return null;

          const value = form[col.field] ?? "";
          const isNumber = col.type === "number";
          const isJsonType = col.type === "object" || col.type === "array";
          const isImage = col.type === "image";
          const numberRange = isNumber ? parseNumberRange(col.range) : null;
          const helper = numberRange
            ? `${numberRange.min}-${numberRange.max}`
            : undefined;
          const fieldError = errors[col.field];

          return (
            <Box key={col.field}>
              <TextField
                label={col.headerName}
                value={value}
                type={isNumber ? "number" : "text"}
                multiline={!isNumber}
                minRows={isJsonType ? 6 : 1}
                inputProps={
                  numberRange
                    ? { min: numberRange.min, max: numberRange.max }
                    : undefined
                }
                error={Boolean(fieldError)}
                helperText={fieldError || helper}
                onChange={(e) => handleChange(col.field, e.target.value)}
                fullWidth
                margin="normal"
              />

              {isImage && typeof value === "string" && value.trim() && (
                <Box
                  component="img"
                  src={value.trim()}
                  alt={col.headerName || "Preview"}
                  sx={{
                    mt: 1,
                    maxWidth: "100%",
                    maxHeight: 220,
                    objectFit: "contain",
                    borderRadius: 1,
                    border: "1px solid",
                    borderColor: "divider",
                  }}
                />
              )}
            </Box>
          );
        })}
      </DialogContent>

      <DialogActions>
        <Button onClick={() => onClose(false)}>Cancel</Button>
        <Button onClick={handleSubmit} variant="contained">
          {isEdit ? "Save" : "Create"}
        </Button>
      </DialogActions>
    </Dialog>
  );
}
