import { Box, Card, CardContent, Chip, Stack, Typography } from "@mui/material";
import CodexPanel from "./CodexPanel";

function formatNumber(value) {
  if (typeof value !== "number") {
    return String(value);
  }
  if (Number.isInteger(value)) {
    return String(value);
  }
  return value.toFixed(2).replace(/\.?0+$/, "");
}

function formatPercent(value) {
  if (typeof value !== "number") {
    return String(value);
  }
  const percentValue = value * 100;
  return `${formatNumber(percentValue)}%`;
}

function formatBuffDebuffStat(label, value, isPercent = false, suffix = "") {
  if (typeof value !== "number") {
    return `${label}: ${String(value)}`;
  }

  const amount = `${isPercent ? formatPercent(Math.abs(value)) : formatNumber(Math.abs(value))}${suffix}`;
  if (value < 0) {
    return `Debuffs ${label} by ${amount}`;
  }
  return `Buffs ${label} by ${amount}`;
}

function formatAbilityValue(value) {
  if (value === null || value === undefined) {
    return ["Value: N/A"];
  }

  if (typeof value !== "object" || Array.isArray(value)) {
    return [`Value: ${String(value)}`];
  }

  const lines = Object.entries(value)
    .filter(([, entryValue]) => entryValue !== null && entryValue !== undefined)
    .map(([key, entryValue]) => {
      switch (key) {
        case "damage":
          return `Damage: ${formatPercent(entryValue)} of attack`;
        case "heal":
          return `Heal: ${formatPercent(entryValue)} of attack`;
        case "damageReduction":
          return formatBuffDebuffStat("Damage Reduction", entryValue, true);
        case "stun":
          return `Stun Duration: ${formatNumber(entryValue)} turn(s)`;
        case "attack":
          return formatBuffDebuffStat("Attack", entryValue);
        case "hp":
          return formatBuffDebuffStat("HP", entryValue, true, " of attack");
        case "speed":
          return formatBuffDebuffStat("Speed", entryValue);
        case "reduceAttack":
          return `Debuffs Attack by ${formatNumber(entryValue)}`;
        case "reduceSpeed":
          return `Debuffs Speed by ${formatNumber(entryValue)}`;
        case "debuff":
          return `Debuffs target by ${formatNumber(Math.abs(entryValue))}`;
        case "aoe":
          return entryValue ? "Targets all applicable targets" : "Targets a single target";
        case "selfOnly":
          return entryValue ? "Can only target self" : "Can target others";
        default:
          return `${key}: ${String(entryValue)}`;
      }
    });

  return lines.length > 0 ? lines : ["Value: N/A"];
}

function AbilityItem({ ability }) {
  const valueLines = formatAbilityValue(ability.value);

  return (
    <Card
      sx={{
        height: 420,
        display: "flex",
        flexDirection: "column",
        border: "2px solid",
        borderColor: "divider",
        borderRadius: 3,
        transition: "0.2s",
        "&:hover": {
          transform: "translateY(-4px) scale(1.02)",
          boxShadow: 6,
        },
      }}
    >
      <CardContent sx={{ display: "flex", flexDirection: "column", flexGrow: 1, overflow: "hidden" }}>
        <Typography fontWeight={700}>{ability.name}</Typography>
        <Typography variant="body2">
          Probability: {ability.probability}
          %
        </Typography>

        <Box sx={{ mt: 1, flexGrow: 1, overflowY: "auto", pr: 1 }}>
          <Typography variant="body2" color="text.secondary">
            {ability.description}
          </Typography>
          <Stack spacing={0.5} sx={{ mt: 1 }}>
            {valueLines.map((line) => (
              <Typography key={line} variant="body2">
                {line}
              </Typography>
            ))}
          </Stack>
        </Box>

        {Array.isArray(ability.types) && ability.types.length > 0 ? (
          <Stack direction="row" spacing={1} sx={{ mt: 1, flexWrap: "wrap" }} useFlexGap>
            {ability.types.map((type) => (
              <Chip key={type} size="small" label={type} />
            ))}
          </Stack>
        ) : null}
      </CardContent>
    </Card>
  );
}

export default function CodexAbilities() {
  return (
    <CodexPanel
      endpoint="/abilities/codex"
      entityKey="Abilities"
      emptyMessage="No abilities found in the codex."
      renderCard={(item) => <AbilityItem ability={item} />}
    />
  );
}
