import { Box, Tab, Tabs } from "@mui/material";
import { useState } from "react";
import CodexAbilities from "./CodexAbilities";
import CodexCards from "./CodexCards";
import CodexEnemies from "./CodexEnemies";

export default function GalleryCodex() {
  const [activeCodex, setActiveCodex] = useState("cards");

  return (
    <Box>
      <Tabs
        value={activeCodex}
        onChange={(_, nextValue) => setActiveCodex(nextValue)}
        sx={{ mb: 3 }}
      >
        <Tab label="Cards" value="cards" />
        <Tab label="Enemies" value="enemies" />
        <Tab label="Abilities" value="abilities" />
      </Tabs>

      {activeCodex === "cards" ? <CodexCards /> : null}
      {activeCodex === "enemies" ? <CodexEnemies /> : null}
      {activeCodex === "abilities" ? <CodexAbilities /> : null}
    </Box>
  );
}
