// src/components/admin/EnemiesTable.jsx
import { useState } from "react";
import DataTable from "./DataTable";
import api from "../../utils/api";
import AdminFormDialog from "./dialogs/AdminFormDialog";

export default function EnemiesTable() {
  const [selectedEnemy, setSelectedEnemy] = useState(null);
  const [open, setOpen] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);
  const [tableState, setTableState] = useState({
    page: 0,
    limit: 10,
    search: "",
  });

  const tableSetters = {
    setPage: (page) => setTableState((prev) => ({ ...prev, page })),
    setLimit: (limit) => setTableState((prev) => ({ ...prev, limit })),
    setSearch: (search) => setTableState((prev) => ({ ...prev, search })),
  };

  const enemyColumns = [
    { field: "name", headerName: "Name" },
    { field: "description", headerName: "Description" },
    { field: "imageUrl", headerName: "Image URL", type: "image" },
    { field: "hp", headerName: "HP", type: "number" },
    { field: "attack", headerName: "Attack", type: "number" },
    { field: "speed", headerName: "Speed", type: "number" },
  ];

  const fetchEnemies = async ({ page, limit, search }) => {
    const params = { page: page + 1, limit, search };
    return await api.get("/enemies", { params });
  };

  const handleEdit = (enemy) => {
    setSelectedEnemy(enemy);
    setOpen(true);
  };

  const handleDelete = async (enemy) => {
    if (confirm(`Delete enemy ${enemy.name}?`)) {
      await api.delete(`/enemies/${enemy._id}`);
      setRefreshKey((prev) => prev + 1);
    }
  };

  return (
    <>
      <DataTable
        fetchData={fetchEnemies}
        columns={enemyColumns}
        onEdit={handleEdit}
        onDelete={handleDelete}
        tableState={tableState}
        tableSetters={tableSetters}
        refreshKey={refreshKey}
      />
      {open && (
        <AdminFormDialog
          entity={selectedEnemy}
          endpoint="/enemies"
          columns={enemyColumns}
          title="Enemy"
          onClose={() => {
            setOpen(false);
            setRefreshKey((prev) => prev + 1);
          }}
        />
      )}
    </>
  );
}
