// src/pages/AdminPanel.jsx
import { useState } from "react";
import { Box, Tabs, Tab, Typography } from "@mui/material";
import CardsTable from "../../components/admin/CardsTable";
import PacksTable from "../../components/admin/PacksTable";
import AbilitiesTable from "../../components/admin/AbilitiesTable";
import EnemiesTable from "../../components/admin/EnemiesTable";
import UsersTable from "../../components/admin/UsersTable";

function TabPanel({ children, value, index }) {
  return value === index ? <Box sx={{ py: 2 }}>{children}</Box> : null;
}

export default function AdminPanel() {
  const [tabIndex, setTabIndex] = useState(0);

  const handleChange = (event, newValue) => {
    setTabIndex(newValue);
  };

  return (
    <Box>
      <Typography variant="h4" gutterBottom>
        Admin Panel
      </Typography>
      <Tabs value={tabIndex} onChange={handleChange}>
        <Tab label="Cards" />
        <Tab label="Abilities" />
        <Tab label="Enemies" />
        <Tab label="Packs" />
        <Tab label="Users" />
      </Tabs>

      <TabPanel value={tabIndex} index={0}>
        <CardsTable />
      </TabPanel>
      <TabPanel value={tabIndex} index={1}>
        <AbilitiesTable />
      </TabPanel>
      <TabPanel value={tabIndex} index={2}>
        <EnemiesTable />
      </TabPanel>
      <TabPanel value={tabIndex} index={3}>
        <PacksTable />
      </TabPanel>
      <TabPanel value={tabIndex} index={4}>
        <UsersTable />
      </TabPanel>
    </Box>
  );
}
